#include <bits/stdc++.h>
using namespace std;

const int N=11,INF=1e8;

int n,m,a[N][N],b[N][N];
int f[1<<20],p[N];

int cal(int x){
    int res=0;
    for(;x;x-=(x&(-x)))
        res++;
    return res;
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++)
            scanf("%d",&a[i][j]);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++)
            scanf("%d",&b[i][j]);
    f[((1<<n)-1)<<m]=0;
    p[0]=m;
    for(int i=(((1<<n)-1)<<m)-1;i;i--){
        if(cal(i)!=n)
            continue;
        int tmp=i,cnt=0;
        for(int j=n;j;j--){
            p[j]=log2(tmp&(-tmp))-(n-j);
            tmp-=tmp&(-tmp);
            cnt+=p[j];
        }
        if(cnt%2==0)
            f[i]=-INF;
        else
            f[i]=INF;
        for(int j=1;j<=n;j++)
            if(p[j]<p[j-1]){
                int nxt=i-(1<<p[j]+(n-j))+(1<<p[j]+1+(n-j));
                if(cnt%2==0)
                    f[i]=max(f[i],f[nxt]+a[j][p[j]+1]);
                else
                    f[i]=min(f[i],f[nxt]-b[j][p[j]+1]);
            }
        /*
        for(int j=1;j<=n;j++)
            printf("%d ",p[j]);
        puts("");
        printf("%d\n",f[i]);
        */
    }
    printf("%d",f[(1<<n)-1]);
    return 0;
}
